mapper.insert:
	 	MERGE INTO NF_REMIT_MGT X
        USING (SELECT COUNT(*) COUNT
                 FROM NF_REMIT_MGT
                WHERE CUST_NO = #{custNo}
                  AND TRAD_NO = #{tradNo} 
                  AND REMIT_DT = TO_CHAR(CURRENT TIMESTAMP,'yyyymmdd')) Y
        ON (Y.COUNT > 0
            AND X.CUST_NO = #{custNo}
            AND X.TRAD_NO = #{tradNo} )
        WHEN MATCHED THEN
        UPDATE SET
           CNTRPRTY_ACCT_NO = #{cntrprtyAcctNo}
           , CNTRPRTY_CD = #{cntrprtyCd}
           , LST_CHNG_DT = CURRENT TIMESTAMP
           , CNTRPRTY_REMIT_REQ_CNT = CNTRPRTY_REMIT_REQ_CNT + 1
           , CNTRPRTY_AUTHNT_CD = #{cntrprtyAuthntCd}
        WHEN NOT MATCHED THEN
        INSERT
         (
           CUST_NO,
           REMIT_DT,
           TRAD_NO,
           CNTRPRTY_ACCT_NO,
           CNTRPRTY_CD,
           CNTRPRTY_AUTHNT_CD,
           LST_CHNG_DT,
           CNTRPRTY_REMIT_REQ_CNT
         ) VALUES (
           #{custNo}, TO_CHAR(CURRENT TIMESTAMP,'yyyymmdd'), #{tradNo}, #{cntrprtyAcctNo}, #{cntrprtyCd}, #{cntrprtyAuthntCd}, CURRENT TIMESTAMP, #{cntrprtyRemitReqCnt}
         )

mapper.update:
		UPDATE 
        	NF_REMIT_MGT
        SET
	         CNTRPRTY_ACCT_NO = #{cntrprtyAcctNo}
	         , CNTRPRTY_CD = #{cntrprtyCd}
	         , LST_CHNG_DT = CURRENT TIMESTAMP
	         , CNTRPRTY_REMIT_REQ_CNT = CNTRPRTY_REMIT_REQ_CNT + 1
	         , CNTRPRTY_AUTHNT_CD = #{cntrprtyAuthntCd}
        WHERE
         	CUST_NO = #{custNo} AND TRAD_NO = #{tradNo}

mapper.select:
SELECT X.RNUM , X.TRAD_NO , X.CNTRPRTY_AUTHNT_CD FROM ( SELECT ROW_NUMBER() OVER(order by TRAD_NO DESC) as RNUM , TRAD_NO , CNTRPRTY_AUTHNT_CD FROM NF_REMIT_MGT WHERE CUST_NO = #{custNo} AND REMIT_DT = TO_CHAR(CURRENT TIMESTAMP, 'YYYYMMDD')
AND TRAD_NO in ( SELECT TRAD_NO FROM NF_TRADINFO_MGT WHERE CUST_NO = #{custNo} AND (TRAD_REG_GB = #{tradRegGb})
AND BIZ_TYPE = #{bizType} AND PRGRSS_STS_CD = 'PRGS'
AND TO_CHAR(INIT_REGIST_DT, 'YYYYMMDD') LIKE TO_CHAR(CURRENT TIMESTAMP, 'YYYYMMDD')
AND TRAD_NO = #{tradNo}
)
) X WHERE RNUM = 1 with ur
